INSERT INTO ce_glossary (id, term, slug, short_definition, full_definition, category, display_order, is_featured, related_terms, tags, created_at, updated_at) VALUES
('0258e24b-c409-4dca-9c63-836112caa64d','PIE','pie','Player Impact Estimate.','PIE is a player impact metric used in CosmicEdge as one contextual quality signal for projection adjustment.','basketball-stat',2,true,'[]','[]','2026-03-06 20:48:00.478669+00','2026-03-06 20:48:00.478669+00'),
('8b97a5b9-6b6a-416b-96ce-57d288ca1b77','Streak Flag','streak-flag','A directional trend label such as OVER_HEATER or UNDER_TREND.','The streak engine classifies recent line-clearing behavior into flags that can slightly adjust projection confidence.','model',4,false,'[]','[]','2026-03-06 20:48:00.478669+00','2026-03-06 20:48:00.478669+00'),
('aedb6661-94af-43f0-badc-a24d536e9b79','Mars Boost','mars-boost','An aggressive or action-oriented astro modifier.','Mars Boost is an astro concept used to represent assertive, high-output, high-activity conditions in the model.','astro',5,true,'[]','[]','2026-03-06 20:48:00.478669+00','2026-03-06 20:48:00.478669+00'),
('5e546a41-90cf-4e11-8e63-921e03a3ceb7','Mercury Chaos','mercury-chaos','An astro volatility modifier.','Mercury Chaos is used to represent instability, randomness, or increased variance in outcomes.','astro',6,true,'[]','[]','2026-03-06 20:48:00.478669+00','2026-03-06 20:48:00.478669+00'),
('c3d6cbb3-cd22-4dff-b873-ff965bf3cb7f','Saturn Clamp','saturn-clamp','A restrictive or suppressive astro modifier.','Saturn Clamp is used to represent tighter, more limited, or lower-ceiling performance conditions.','astro',7,true,'[]','[]','2026-03-06 20:48:00.478669+00','2026-03-06 20:48:00.478669+00'),
('98780860-eaf8-47ef-8270-f273a18ccfa3','Jupiter Lift','jupiter-lift','An expansion or upside modifier.','Jupiter Lift represents buoyant, expansive, or favorable upside conditions in the model.','astro',8,true,'[]','[]','2026-03-06 20:48:00.478669+00','2026-03-06 20:48:00.478669+00'),
('eda75dbe-0a07-4895-8c72-5581796988fd','Neptune Fog','neptune-fog','A noise or uncertainty modifier.','Neptune Fog represents unclear, unstable, or low-clarity situations that can reduce model confidence.','astro',9,true,'[]','[]','2026-03-06 20:48:00.478669+00','2026-03-06 20:48:00.478669+00'),
('ced12778-3123-41d8-9c8b-3de8deb0dceb','Sky Noise','sky-noise','A volatility bucket used in the astro layer.','Sky Noise is a descriptive variance bucket that can widen or tighten expected outcome behavior.','astro',10,true,'[]','[]','2026-03-06 20:48:00.478669+00','2026-03-06 20:48:00.478669+00'),
('5b0cc45c-d0d0-4835-bba2-898636de12ff','Hit Rate','hit-rate','Percentage of recent games where the player exceeded the book line for a given stat.','Hit rate is computed over L5, L10, and L20 game windows. A hit rate of 0.80 over L10 means the player exceeded the line in 8 of their last 10 games. This is a core input to the Edge Score calculation.','model',12,true,'[]','[]','2026-03-11 15:24:24.871433+00','2026-03-11 15:24:24.871433+00'),
('c86940f7-da00-402b-b90b-01a347696a71','Rolling Average','rolling-average','Mean stat value computed over a sliding window of recent games (L5, L10, L20, season).','Rolling averages smooth out single-game variance and reveal short-term trends. The L5 average is most reactive to recent form, while the season average provides the baseline. The delta between L5 and season is a key momentum signal.','model',13,false,'[]','[]','2026-03-11 15:24:24.871433+00','2026-03-11 15:24:24.871433+00'),
('8ee68ad1-a666-47a1-ad0b-c93feb5db121','Pace','pace','Estimated number of possessions per 48 minutes for a team.','Higher pace means more possessions, which generally inflates counting stats (points, rebounds, assists). CosmicEdge uses team pace data to adjust projections for game environment — a high-pace matchup naturally boosts stat expectations.','basketball-stat',14,true,'[]','[]','2026-03-11 15:24:24.871433+00','2026-03-11 15:24:24.871433+00'),
('00d56c21-df9a-4f8a-bcff-ce09f39c5c68','Usage Rate','usage-rate','Percentage of team possessions a player uses while on the floor.','High usage players handle more shots, drives, and touches. A sudden usage increase (role change) often precedes stat breakouts. CosmicEdge tracks usage shifts by comparing L5 FGA to season average.','basketball-stat',15,false,'[]','[]','2026-03-11 15:24:24.871433+00','2026-03-11 15:24:24.871433+00'),
('2ef049ea-5a58-4437-aeeb-41558b1d4d3f','Offensive Rating','off-rating','Points scored per 100 possessions by a team or player.','Offensive rating normalizes scoring output by pace, allowing fair comparison between fast and slow teams. It is a key input to the game prediction model for estimating expected team totals.','basketball-stat',16,false,'[]','[]','2026-03-11 15:24:24.871433+00','2026-03-11 15:24:24.871433+00'),
('d8e1dc46-e7ec-4323-8879-57efcc19dd39','Defensive Rating','def-rating','Points allowed per 100 possessions by a team.','Lower defensive rating = better defense. CosmicEdge uses opponent defensive rating as a matchup difficulty modifier — a player facing a top-5 defense has their projection dampened accordingly.','basketball-stat',17,false,'[]','[]','2026-03-11 15:24:24.871433+00','2026-03-11 15:24:24.871433+00'),
('be142e3f-fb7e-4603-88c3-3f94d7a26432','Net Rating','net-rating','Offensive rating minus defensive rating. Measures overall team quality.','A net rating of +10 means the team outscores opponents by 10 points per 100 possessions. Large net rating differentials between opponents increase blowout risk, which affects late-game minutes and stat accumulation.','basketball-stat',18,false,'[]','[]','2026-03-11 15:24:24.871433+00','2026-03-11 15:24:24.871433+00'),
('82189859-bbe8-4bdf-a320-84962d8c6cf4','Monte Carlo','monte-carlo','A simulation technique that runs thousands of random trials to estimate probability distributions.','CosmicEdge runs 5,000–10,000 Monte Carlo iterations per prop, sampling from the player adjusted distribution. The percentage of trials exceeding the book line becomes the simulated over probability. This captures tail risk better than a simple mean comparison.','model',19,true,'[]','[]','2026-03-11 15:24:24.871433+00','2026-03-11 15:24:24.871433+00'),
('faa2c42b-3061-4f93-83cf-243c9125b19b','Blowout Risk','blowout-risk','Probability that a game becomes lopsided, reducing starters minutes in the 4th quarter.','When the net rating differential between two teams is large, blowout risk increases. This reduces expected minutes for starters and compresses their stat ceilings. CosmicEdge factors this into projection adjustments.','model',20,false,'[]','[]','2026-03-11 15:24:24.871433+00','2026-03-11 15:24:24.871433+00'),
('b8223622-e411-4cbd-8a34-427c9338b453','Transit','transit','Current position of a planet relative to a natal chart position.','Transits are the primary dynamic factor in astrological analysis. Mars transiting a player natal Sun may boost aggression and scoring. Saturn transiting the same point may impose discipline or restriction. CosmicEdge evaluates daily transits for all players with known birth data.','astro',21,false,'[]','[]','2026-03-11 15:24:24.871433+00','2026-03-11 15:24:24.871433+00'),
('c7b1c57f-f0ec-4cb7-ba03-fe893acfec6e','Horary Chart','horary-chart','An astrology chart cast for the exact moment and location a question is asked or a game begins.','In CosmicEdge, horary charts are cast at game tip-off time and venue. The 1st house ruler represents the home team, the 7th house ruler represents the away team. Dignities, receptions, and lunar aspects determine the horary verdict.','astro',22,true,'[]','[]','2026-03-11 15:24:24.871433+00','2026-03-11 15:24:24.871433+00'),
('1ede89c9-2dda-4ccd-b344-51644a8a393f','Void of Course Moon','voc-moon','A period when the Moon makes no major aspects before leaving its current sign.','VOC Moon periods are traditionally associated with inaction and unpredictability. In sports, this can signal chaotic, low-scoring, or unexpected outcomes. CosmicEdge flags VOC Moon periods in game analysis.','astro',23,false,'[]','[]','2026-03-11 15:24:24.871433+00','2026-03-11 15:24:24.871433+00'),
('7cc7c97e-f718-4138-8450-cea9863d6ffe','Confidence Tier','confidence-tier','S/A/B/C rating based on Edge Score magnitude, sample size, and variance.','Confidence tiers categorize the strength of a prop projection based on Edge Radar score: Elite (70+, gold) — highest conviction plays; Strong (60–69, green) — solid analytical case; Playable (55–59, blue) — marginal but positive edge; Neutral (below 55, gray) — no clear edge detected.','model',11,true,'[]','[]','2026-03-11 15:24:24.871433+00','2026-03-11 15:24:24.871433+00'),
('cf399636-485d-4ee9-93ae-66047febac73','Planetary Hour','planetary-hour','A system dividing daylight and nightlight into segments ruled by classical planets.','Each hour of the day is ruled by a planet (Sun, Moon, Mars, Mercury, Jupiter, Venus, Saturn). CosmicEdge evaluates whether the planetary hour at game time aligns favorably with team or player natal signatures.','astro',24,false,'[]','[]','2026-03-11 15:24:24.871433+00','2026-03-11 15:24:24.871433+00'),
('daa91db4-b105-4c62-a54d-77db645c7cbc','PRA','pra','Points + Rebounds + Assists combined stat.','PRA is a popular combo market that captures overall production. Because it aggregates three stats, it tends to have lower variance than individual markets, making it a favorite for modeling.','basketball-stat',25,false,'[]','[]','2026-03-11 15:24:24.871433+00','2026-03-11 15:24:24.871433+00'),
('5f69c2ed-e76f-4890-aeca-5098d282f590','Edge Score','edge-score','A rank-style score representing the strength of a prop versus its line.','Edge Score measures the difference between the model projection and the sportsbook line. Formula: EdgeScore = Projection − Line. Positive edge → value on Over. Negative edge → value on Under. Higher edges indicate stronger theoretical value. The score is further refined through simulation probability and signal alignment into confidence tiers.','model',1,true,'[]','[]','2026-03-06 20:48:00.478669+00','2026-03-06 20:48:00.478669+00'),
('0e707bf6-7fe9-4ad2-8fb4-87123fef6d8a','Momentum','momentum','A measure of recent trend versus longer baseline.','Momentum measures whether a player is trending upward or downward. Formula: Momentum = Last5Average − SeasonAverage. Positive momentum → player performing above baseline. Negative momentum → regression signal. The Momentum Engine converts this into an adjustment multiplier capped between 0.90 and 1.10.','model',3,true,'[]','[]','2026-03-06 20:48:00.478669+00','2026-03-06 20:48:00.478669+00'),
('efae015b-0aed-40d8-88cc-ecb95e14f186','Projection','projection','The model''s predicted stat outcome for a player.','Calculated using historical performance, pace normalization, usage rates, matchup difficulty, and trend signals. Base formula: (Season Avg × 0.50) + (Last 10 Avg × 0.30) + (Last 5 Avg × 0.20).','model',1,true,'[]','[]','2026-03-11 16:10:31.529472+00','2026-03-11 16:10:31.529472+00'),
('22d10bed-61b2-43fc-9614-075c7521357e','Over Heater','over-heater','Player consistently exceeding a sportsbook line in recent games.','Triggered when over rate in last 5 games ≥ 80%. Indicates sustained above-line performance the market may not have adjusted to.','model',5,true,'[]','[]','2026-03-11 16:10:31.529472+00','2026-03-11 16:10:31.529472+00'),
('f136605a-27f2-47bd-a7dd-ad9bddee7f9f','Usage Spike','usage-spike','Recent increase in offensive involvement.','Detected by comparing recent usage against season baseline. A significant increase suggests expanded role or opportunity.','model',6,true,'[]','[]','2026-03-11 16:10:31.529472+00','2026-03-11 16:10:31.529472+00'),
('5da15ddd-9afc-4312-833c-f3233b101cc6','Defense Edge','defense-edge','Matchup weakness in a defense against a particular stat.','Example: Opponent ranks 28th in rebounding defense → positive rebound adjustment. Formula: DefenseEdge = LeagueAvgAllowed − OpponentAllowed.','model',7,true,'[]','[]','2026-03-11 16:10:31.529472+00','2026-03-11 16:10:31.529472+00'),
('ad92eb19-0e2f-4d29-8334-f22a5a1ae70e','Pace Boost','pace-boost','Game tempo expected to increase stat opportunities.','PaceImpact = GamePace − LeagueAveragePace. Higher pace means more possessions and generally inflates volume stats.','model',8,false,'[]','[]','2026-03-11 16:10:31.529472+00','2026-03-11 16:10:31.529472+00'),
('9e65df07-9646-4546-94bb-8d287275d078','Volatility','volatility','Performance variance measured by standard deviation.','Higher volatility means wider stat distribution. Formula: Volatility = StdDev(RecentGames). Widens simulation confidence bands.','model',9,false,'[]','[]','2026-03-11 16:10:31.529472+00','2026-03-11 16:10:31.529472+00'),
('54cbccaf-3a44-4892-ba1c-de4c2dbb1b88','Consistency Score','consistency-score','Measures reliability of stat production.','Formula: ConsistencyScore = 1 − (Volatility / MeanStat). Higher scores indicate more predictable performance.','model',10,false,'[]','[]','2026-03-11 16:10:31.529472+00','2026-03-11 16:10:31.529472+00'),
('f7d8e8c0-6469-42a2-8852-866c87763e6e','Line Value','line-value','Measures sportsbook line inefficiency.','Formula: LineValue = MarketLine − ConsensusProjection. Identifies pricing divergence from model expectations.','model',11,false,'[]','[]','2026-03-11 16:10:31.529472+00','2026-03-11 16:10:31.529472+00'),
('bfcff934-8c6f-4ada-b287-f00954a676c8','Market Pressure','market-pressure','Detects betting market movement and sharp action.','Tracks line movement, public bet %, and sharp indicators to gauge if a line moves toward or away from model value.','model',12,false,'[]','[]','2026-03-11 16:10:31.529472+00','2026-03-11 16:10:31.529472+00'),
('a82e2069-eeec-4b70-91fd-b6cbd77990b3','Mercury Precision','mercury-precision','Heightened focus and decision accuracy.','Effects: improved assists, efficient shooting, strong playmaking. Mercury transit enhancing coordination and mental sharpness.','astro',20,false,'[]','[]','2026-03-11 16:10:31.529472+00','2026-03-11 16:10:31.529472+00'),
('3d3248b3-43f7-4e4b-9d3b-f48f1a8445ba','Mercury Retrograde','mercury-retrograde','Disrupted rhythm or execution.','Effects: increased turnovers, missed timing, inconsistent stats. Associated with communication breakdowns and errors.','astro',21,false,'[]','[]','2026-03-11 16:10:31.529472+00','2026-03-11 16:10:31.529472+00'),
('2ed0cae2-3cba-4bf1-a5f9-1f1ae1870834','Mars Surge','mars-surge','High physical intensity and scoring drive.','Effects: increased shot attempts, high pace involvement, aggressive stat accumulation. Mars governs energy and aggression.','astro',22,true,'[]','[]','2026-03-11 16:10:31.529472+00','2026-03-11 16:10:31.529472+00'),
('3693393d-d049-4833-b19b-132a155f1c67','Mars Clash','mars-clash','Highly competitive game environment.','Effects: defensive intensity increases, fouls increase, volatility rises. Mars transit elevating combativeness.','astro',23,false,'[]','[]','2026-03-11 16:10:31.529472+00','2026-03-11 16:10:31.529472+00'),
('f0fb2afc-ffc4-4ce4-9223-9cc385d601d6','Jupiter Overdrive','jupiter-overdrive','Extremely favorable performance alignment.','Effects: breakout stat nights, multi-category production. Intensified Jupiter Lift signaling exceptional expansion.','astro',24,false,'[]','[]','2026-03-11 16:10:31.529472+00','2026-03-11 16:10:31.529472+00'),
('7922dc50-9033-434f-84ca-45615fda7d00','Saturn Discipline','saturn-discipline','Structured defensive gameplay.','Effects: lower scoring games, tighter rotations. Saturn creates restriction and methodical play patterns.','astro',25,false,'[]','[]','2026-03-11 16:10:31.529472+00','2026-03-11 16:10:31.529472+00'),
('78253fdc-a3cc-4092-a567-999a518aed3c','Venus Flow','venus-flow','Smooth offensive rhythm and chemistry.','Effects: high assist potential, strong team coordination, fluid ball movement. Venus governs flow and creative expression.','astro',26,false,'[]','[]','2026-03-11 16:10:31.529472+00','2026-03-11 16:10:31.529472+00'),
('b678c448-c6e4-4f90-bbb8-96befb30abbd','Venus Harmony','venus-harmony','Team chemistry alignment.','Effects: balanced stat distribution, cooperative dynamics. Peak Venus influence creating team synergy.','astro',27,false,'[]','[]','2026-03-11 16:10:31.529472+00','2026-03-11 16:10:31.529472+00'),
('ef343803-0850-4daf-817b-83b3dde69a98','Lunar Surge','lunar-surge','Emotional performance spike.','Effects: strong energy games, momentum swings. Moon governs emotion and can amplify performance through intensity.','astro',28,false,'[]','[]','2026-03-11 16:10:31.529472+00','2026-03-11 16:10:31.529472+00'),
('a9d02b0e-8d74-403d-ac2a-2376634a642d','Lunar Drift','lunar-drift','Energy fluctuations and inconsistency.','Effects: inconsistent stat lines, wavering focus. Lunar influence creating unpredictable energy levels.','astro',29,false,'[]','[]','2026-03-11 16:10:31.529472+00','2026-03-11 16:10:31.529472+00'),
('9fe3ede9-e37c-46e6-9d19-f17cb242c626','Eclipse Event','eclipse-event','Extreme volatility environment.','Effects: unpredictable stat distribution, massive outliers possible. Eclipse windows create the most chaotic conditions.','astro',30,true,'[]','[]','2026-03-11 16:10:31.529472+00','2026-03-11 16:10:31.529472+00'),
('a035ab24-3a9d-4da1-b7c9-23f62dba36e8','Momentum Rising','momentum-rising','Recent stat acceleration above season average.','Combined analytics + trend signal. Detected when Last5Average significantly exceeds SeasonAverage.','signal',31,true,'[]','[]','2026-03-11 16:10:31.529472+00','2026-03-11 16:10:31.529472+00'),
('4361c8e5-0e47-4df0-bfd3-38c33f09839f','Shootout Script','shootout-script','High-scoring, high-possession game environment.','Boosts PTS, AST, 3PM, PRA. Indicators: fast pace, strong offenses, weak perimeter defense, high total.','game-script',40,false,'[]','[]','2026-03-11 16:10:31.529472+00','2026-03-11 16:10:31.529472+00'),
('6a770804-dd16-4201-bdfa-e576a7813b09','Defensive Grind','defensive-grind','Low pace, tough scoring environment.','Favors REB, BLK, STL, unders on points. Indicators: low total, strong defenses, slow pace, physical matchup.','game-script',41,false,'[]','[]','2026-03-11 16:10:31.529472+00','2026-03-11 16:10:31.529472+00'),
('fa48ce68-65a2-4f5b-84e6-f1d36c03160c','Tight Game','tight-game','Competitive game expected to stay close.','Boosts star minutes, late-game scoring, assists, clutch usage. Indicators: small spread, evenly matched teams.','game-script',43,false,'[]','[]','2026-03-11 16:10:31.529472+00','2026-03-11 16:10:31.529472+00'),
('926015b1-4ee5-4efe-a1b2-781daa46f4ba','OT Candidate','ot-candidate','Game with elevated overtime probability.','Boosts all volume stats: PTS, AST, REB, PRA. Indicators: close spread, high star usage, frequent close finishes.','game-script',44,false,'[]','[]','2026-03-11 16:10:31.529472+00','2026-03-11 16:10:31.529472+00'),
('209c7508-5328-4db7-b6cf-c93808e176c7','Script Shift','script-shift','Live game environment change detected.','During a live game, the dominant script may shift (e.g., from Balanced to Tight Game), affecting prop projections in real time.','game-script',45,false,'[]','[]','2026-03-11 16:10:31.529472+00','2026-03-11 16:10:31.529472+00'),
('033b74dd-ede5-4606-a536-f36c1a828293','Edge Radar','edge-radar','Composite score combining multiple signals into a 0–100 rating.','Formula: EdgeRadar = (ProjectionEdge × 0.35) + (SimulationProb × 0.25) + (TrendScore × 0.15) + (MatchupScore × 0.15) + (SignalScore × 0.10). Tiers: Elite 70+, Strong 60–69, Playable 55–59, Neutral below 55.','model',2,true,'[]','[]','2026-03-11 16:10:31.529472+00','2026-03-11 16:10:31.529472+00'),
('8b6e48df-87b8-43ea-ac06-669f47249c7e','Correlation','correlation','Detects correlated stat outcomes within a game.','Example: High-scoring game → more assists. CorrelationScore is added to projection for related stats.','model',13,false,'[]','[]','2026-03-11 16:10:31.529472+00','2026-03-11 16:10:31.529472+00'),
('4ab67df9-0158-4fa8-9bfb-b3233d8bef72','Blowout Script','blowout-script','Uneven game with large expected margin.','Stars may lose late-game minutes, bench volatility increases. First-half overs more reliable than full-game.','game-script',42,false,'[]','[]','2026-03-11 16:10:31.529472+00','2026-03-11 16:10:31.529472+00')
INSERT INTO ce_formulas (id, formula_name, slug, formula_text, plain_english, category, display_order, is_featured, variables, example_input, example_output, notes, created_at, updated_at) VALUES
('629aeadc-a30e-4890-af65-cdc34bf4fb17','Logistic Probability','logistic-probability','1 / (1 + exp(-k * ((projection - line) / std_dev)))','Converts the gap between projection and line into a probability-like score using volatility.','core',1,true,'{"k": "sensitivity constant", "line": "market line", "std_dev": "expected volatility", "projection": "adjusted projected output"}','{}','{}',NULL,'2026-03-06 20:48:14.845862+00','2026-03-06 20:48:14.845862+00'),
('0a273c1f-cec3-436d-ac11-4994749b9ef6','Edge Score Core','edge-score-core','round(probability * 100)','Turns the core probability into an easy ranking number.','core',2,true,'{"probability": "model probability-like score"}','{}','{}',NULL,'2026-03-06 20:48:14.845862+00','2026-03-06 20:48:14.845862+00'),
('2aac7d52-6605-45d9-a9d6-1ba272f19d56','Momentum Multiplier','momentum-multiplier','greatest(0.90, least(1.10, 1 + momentum_score * 0.02))','Slightly boosts or dampens projection based on recent trend.','modifier',3,true,'{"momentum_score": "recent performance minus baseline"}','{}','{}',NULL,'2026-03-06 20:48:14.845862+00','2026-03-06 20:48:14.845862+00'),
('53e8329e-8377-40ad-8a89-0b02411f7873','Streak Multiplier','streak-multiplier','OVER_HEATER -> 1.06, UNDER_HEATER -> 0.94, OVER_TREND -> 1.03, UNDER_TREND -> 0.97, else 1.00','Applies a small directional boost or dampener from recent streak behavior.','modifier',4,true,'{"streak_flag": "recent trend classification"}','{}','{}',NULL,'2026-03-06 20:48:14.845862+00','2026-03-06 20:48:14.845862+00'),
('d2aa9bbe-d201-4b21-8e7f-0116eaab3b22','Usage Shift Multiplier','usage-shift-multiplier','avg_pra_10 vs avg_pra_season -> 1.10 / 1.05 / 1.00 / 0.97','Uses recent usage surge or drop as a projection multiplier.','modifier',5,true,'{"avg_pra_10": "recent PRA average", "avg_pra_season": "longer baseline PRA average"}','{}','{}',NULL,'2026-03-06 20:48:14.845862+00','2026-03-06 20:48:14.845862+00'),
('143f9d0a-5e02-429e-83b3-ae975a594fdc','Defense Difficulty Multiplier','defense-difficulty-multiplier','opponent stat allowance / league stat allowance, clamped to 0.90–1.10','Adjusts projection based on how permissive the defense is for that stat type.','modifier',6,true,'{"league_allowed": "league average allowance", "opponent_allowed": "opponent recent allowance"}','{}','{}',NULL,'2026-03-06 20:48:14.845862+00','2026-03-06 20:48:14.845862+00'),
('b44accaa-e539-4a8e-8fb9-db5b24fce47b','Naive Joint Probability','parlay-naive-joint-prob','leg_prob_a * leg_prob_b','The base independent estimate for a two-leg parlay before correlation adjustment.','parlay',7,true,'{"leg_prob_a": "first leg probability", "leg_prob_b": "second leg probability"}','{}','{}',NULL,'2026-03-06 20:48:14.845862+00','2026-03-06 20:48:14.845862+00'),
('42f7272d-98ce-4651-80bd-3cbe17c8ff96','Adjusted Joint Probability','parlay-adjusted-joint-prob','naive_joint_prob * correlation_adjustment','Adjusts a two-leg parlay estimate using pair relationship information.','parlay',8,true,'{"naive_joint_prob": "independent parlay probability", "correlation_adjustment": "positive or negative pair modifier"}','{}','{}',NULL,'2026-03-06 20:48:14.845862+00','2026-03-06 20:48:14.845862+00'),
('5ada484e-c3e4-42dd-8d61-06d6b8998884','Hit Rate','hit-rate','hit_rate_L{N} = count(stat > line) / N','Fraction of the last N games where the player exceeded the book line.','core',9,false,'{"N": "Window size (5, 10, 20)", "line": "Book line", "stat": "Player stat value"}','{}','{}',NULL,'2026-03-11 15:24:40.899062+00','2026-03-11 15:24:40.899062+00'),
('97d169bb-7c37-4801-a680-cccbb69717ce','Coefficient of Variation','cv','CV = σ / μ','Standard deviation divided by mean — measures consistency. Lower CV means more predictable performance.','modifier',10,false,'{"μ": "Mean of last 10 games", "σ": "Standard deviation of last 10 games"}','{}','{}',NULL,'2026-03-11 15:24:40.899062+00','2026-03-11 15:24:40.899062+00'),
('0e5838a3-edd1-40d4-ae42-f38fad39257b','Blowout Risk','blowout-risk','blowout_risk = min(1, |home_net_rtg - away_net_rtg| / 30)','Probability of a lopsided game based on net rating differential between teams.','core',11,false,'{"away_net_rtg": "Away team net rating", "home_net_rtg": "Home team net rating"}','{}','{}',NULL,'2026-03-11 15:24:40.899062+00','2026-03-11 15:24:40.899062+00'),
('d449c99a-0aba-41f5-8f5c-517f7ce23082','Win Probability (Live)','live-wp','WP = 1 / (1 + exp(-z)) where z = β₁·(SD/σ)·ln((T+1)/(R+1)) + β₃·pos·√(e/T) + β₄·√(e/T)','Live win probability based on score differential, time remaining, and possession.','core',12,true,'{"R": "Time remaining", "T": "Total game time (sec)", "e": "Elapsed time", "SD": "Score differential", "σ": "Sport-specific scoring std dev", "pos": "Possession indicator"}','{}','{}',NULL,'2026-03-11 15:24:40.899062+00','2026-03-11 15:24:40.899062+00'),
('42c829db-4806-4200-b1c6-ff4ade3cae9e','Pace Adjustment','pace-adj','pace_factor = matchup_pace / league_avg_pace','Scales projections based on expected game tempo relative to league average.','modifier',13,false,'{"matchup_pace": "Average of both teams pace", "league_avg_pace": "League average pace (≈100)"}','{}','{}',NULL,'2026-03-11 15:24:40.899062+00','2026-03-11 15:24:40.899062+00'),
('2c477c23-a2d8-450d-8e13-79ffc5cb0540','Edge Radar','edge-radar','(ProjectionEdge × 0.35) + (SimulationProb × 0.25) + (TrendScore × 0.15) + (MatchupScore × 0.15) + (SignalScore × 0.10)','Combines projection edge, simulation probability, trend, matchup, and signal scores into a final 0–100 composite rating.','core',2,true,'{"TrendScore": "momentum + streak score", "SignalScore": "active signal count weight", "MatchupScore": "defense difficulty factor", "ProjectionEdge": "normalized edge score", "SimulationProb": "Monte Carlo probability"}','{}','{}',NULL,'2026-03-11 16:11:08.664462+00','2026-03-11 16:11:08.664462+00'),
('fc60b976-6120-48d4-9898-d2c1dc045370','Base Projection','base-projection','(SeasonAvg × 0.50) + (Last10Avg × 0.30) + (Last5Avg × 0.20)','Weighted average combining season-long baseline with recency-biased windows.','core',3,true,'{"Last5Avg": "last 5 games average", "Last10Avg": "last 10 games average", "SeasonAvg": "full season average"}','{}','{}',NULL,'2026-03-11 16:11:08.664462+00','2026-03-11 16:11:08.664462+00'),
('d1f97e87-28d2-4888-a3cd-33631c626eaa','NebulaProp v2','nebula-prop-v2','BaseProjection + MomentumAdj + UsageAdj + MatchupAdj + PaceAdj + StreakAdj','The primary prop model combining all adjustment layers.','core',4,true,'{"PaceAdj": "game tempo impact", "UsageAdj": "role change adjustment", "StreakAdj": "streak behavior factor", "MatchupAdj": "defense difficulty", "MomentumAdj": "recent form adjustment", "BaseProjection": "weighted player average"}','{}','{}',NULL,'2026-03-11 16:11:08.664462+00','2026-03-11 16:11:08.664462+00'),
('5afa6963-bd3d-48cf-83f1-ec52dc128fe5','Usage Change','usage-change','UsageAdj = (RecentUsage − SeasonUsage) × ImpactFactor','Measures change in offensive opportunity.','modifier',7,false,'{"RecentUsage": "recent usage rate", "SeasonUsage": "season usage rate", "ImpactFactor": "stat-specific sensitivity"}','{}','{}',NULL,'2026-03-11 16:11:08.664462+00','2026-03-11 16:11:08.664462+00'),
('4b20ac51-1f20-4dbd-bd21-9298b30018e5','Matchup Adjustment','matchup-adj','MatchupAdj = OpponentStatRankFactor × DefenseWeight','Adjusts projection based on opponent defensive weakness.','modifier',8,false,'{"DefenseWeight": "category-specific weight", "OpponentStatRankFactor": "opponent rank-based factor"}','{}','{}',NULL,'2026-03-11 16:11:08.664462+00','2026-03-11 16:11:08.664462+00'),
('7c9c0ee6-3884-4430-9b59-883ec137eeb6','Pace Impact','pace-impact','PaceImpact = GamePace − LeagueAveragePace','Higher pace increases stat opportunity.','modifier',9,false,'{"GamePace": "expected game pace", "LeagueAveragePace": "league average pace (100)"}','{}','{}',NULL,'2026-03-11 16:11:08.664462+00','2026-03-11 16:11:08.664462+00'),
('e2a14793-5b61-4510-b901-ca1b9bba98ee','Streak Score','streak-score','StreakScore = RecentOvers / RecentGames','Measures repeated outcomes.','modifier',10,false,'{"RecentGames": "recent game window", "RecentOvers": "times cleared line recently"}','{}','{}',NULL,'2026-03-11 16:11:08.664462+00','2026-03-11 16:11:08.664462+00'),
('a92235ea-c8b0-4730-b5c8-75f831cb26bb','Simulation Engine','simulation-engine','Monte Carlo: N iterations of Normal(mu, sigma) → P(stat > line)','Runs simulations of stat outcomes.','core',11,true,'{"N": "iteration count", "mu": "projected stat mean", "line": "sportsbook line", "sigma": "projected std dev"}','{}','{}',NULL,'2026-03-11 16:11:08.664462+00','2026-03-11 16:11:08.664462+00'),
('60836a0d-6865-4447-8f9f-b2bd2e76b86e','Volatility Index','volatility-index','Volatility = StdDev(RecentGames)','Measures performance variance.','modifier',12,false,'{"RecentGames": "stat values from recent games"}','{}','{}',NULL,'2026-03-11 16:11:08.664462+00','2026-03-11 16:11:08.664462+00'),
('f510d462-15b7-4070-bd6d-8566db5854cb','Consistency','consistency','1 − (Volatility / MeanStat)','Measures reliability.','modifier',13,false,'{"MeanStat": "average stat value", "Volatility": "standard deviation"}','{}','{}',NULL,'2026-03-11 16:11:08.664462+00','2026-03-11 16:11:08.664462+00'),
('10d141b0-65f3-44b6-9b31-60733650d8b2','Defense Edge','defense-edge','DefenseEdge = LeagueAvgAllowed − OpponentAllowed','Positive when opponent allows more than league average.','modifier',14,false,'{"OpponentAllowed": "opponent stat allowed", "LeagueAvgAllowed": "league avg stat allowed"}','{}','{}',NULL,'2026-03-11 16:11:08.664462+00','2026-03-11 16:11:08.664462+00'),
('40095ead-8fc6-46eb-9612-c172bf26b5c1','Line Value','line-value','LineValue = MarketLine − ConsensusProjection','Identifies sportsbook pricing inefficiency.','core',15,false,'{"MarketLine": "sportsbook line", "ConsensusProjection": "model consensus projection"}','{}','{}',NULL,'2026-03-11 16:11:08.664462+00','2026-03-11 16:11:08.664462+00'),
('b279ded0-1dd8-4e6f-80f3-7d445efd3b35','Game Script Simulator','game-script-sim','ScriptAdj = Σ(ScriptProb_i × StatWeight_i)','Simulates game environments and applies script-based adjustments.','core',16,true,'{"ScriptProb": "normalized probability per script", "StatWeight": "stat-specific script sensitivity"}','{}','{}',NULL,'2026-03-11 16:11:08.664462+00','2026-03-11 16:11:08.664462+00'),
('48b9d1f5-504a-48fa-aeb0-945b5006f628','Fatigue Adjustment','fatigue-adj','FatigueAdj = f(BackToBack, MinutesLastGame, TravelDistance)','Reduces projection when fatigue indicators are present.','modifier',17,false,'{"BackToBack": "boolean", "TravelDistance": "miles traveled", "MinutesLastGame": "minutes played"}','{}','{}',NULL,'2026-03-11 16:11:08.664462+00','2026-03-11 16:11:08.664462+00'),
('87447623-efe9-40d8-8776-2c40dfb1ee50','Correlation Score','correlation-score','CorrelationAdj = CorrelationCoeff × ExpectedGameEnvironment','Detects correlated outcomes.','modifier',18,false,'{"CorrelationCoeff": "stat pair correlation", "ExpectedGameEnvironment": "game tempo/total factor"}','{}','{}',NULL,'2026-03-11 16:11:08.664462+00','2026-03-11 16:11:08.664462+00')
